(function () {
  "use strict";

  const VERSION = 4;
  const MODULE_COUNT = 33;
  const DATA_CODEWORDS = 64;
  const ECC_CODEWORDS_PER_BLOCK = 18;
  const BLOCKS = 2;
  const DATA_CODEWORDS_PER_BLOCK = 32;
  const DEFAULT_SIZE = 328;

  const EXP = new Array(512);
  const LOG = new Array(256);
  let value = 1;
  for (let i = 0; i < 255; i += 1) {
    EXP[i] = value;
    LOG[value] = i;
    value <<= 1;
    if (value & 0x100) value ^= 0x11d;
  }
  for (let i = 255; i < 512; i += 1) EXP[i] = EXP[i - 255];

  function gfMul(a, b) {
    if (a === 0 || b === 0) return 0;
    return EXP[LOG[a] + LOG[b]];
  }

  function rsGenerator(degree) {
    let poly = [1];
    for (let i = 0; i < degree; i += 1) {
      const next = new Array(poly.length + 1).fill(0);
      for (let j = 0; j < poly.length; j += 1) {
        next[j] ^= poly[j];
        next[j + 1] ^= gfMul(poly[j], EXP[i]);
      }
      poly = next;
    }
    return poly;
  }

  const RS_GENERATOR = rsGenerator(ECC_CODEWORDS_PER_BLOCK);

  function reedSolomon(data) {
    const result = new Array(ECC_CODEWORDS_PER_BLOCK).fill(0);
    for (const byte of data) {
      const factor = byte ^ result.shift();
      result.push(0);
      for (let i = 0; i < ECC_CODEWORDS_PER_BLOCK; i += 1) {
        result[i] ^= gfMul(RS_GENERATOR[i + 1], factor);
      }
    }
    return result;
  }

  function appendBits(bits, val, len) {
    for (let i = len - 1; i >= 0; i -= 1) bits.push((val >>> i) & 1);
  }

  function makeDataCodewords(text) {
    const bytes = Array.from(new TextEncoder().encode(String(text)));
    if (bytes.length > 62) {
      throw new Error("QR invite URL is too long for local QRCode version 4-M.");
    }
    const bits = [];
    appendBits(bits, 0x4, 4);
    appendBits(bits, bytes.length, 8);
    for (const byte of bytes) appendBits(bits, byte, 8);
    const maxBits = DATA_CODEWORDS * 8;
    appendBits(bits, 0, Math.min(4, maxBits - bits.length));
    while (bits.length % 8 !== 0) bits.push(0);

    const data = [];
    for (let i = 0; i < bits.length; i += 8) {
      data.push(bits.slice(i, i + 8).reduce((sum, bit) => (sum << 1) | bit, 0));
    }
    for (let pad = 0xec; data.length < DATA_CODEWORDS; pad ^= 0xfd) data.push(pad);
    return data;
  }

  function makeCodewords(text) {
    const data = makeDataCodewords(text);
    const blocks = [];
    for (let i = 0; i < BLOCKS; i += 1) {
      const blockData = data.slice(i * DATA_CODEWORDS_PER_BLOCK, (i + 1) * DATA_CODEWORDS_PER_BLOCK);
      blocks.push({ data: blockData, ecc: reedSolomon(blockData) });
    }

    const result = [];
    for (let i = 0; i < DATA_CODEWORDS_PER_BLOCK; i += 1) {
      for (const block of blocks) result.push(block.data[i]);
    }
    for (let i = 0; i < ECC_CODEWORDS_PER_BLOCK; i += 1) {
      for (const block of blocks) result.push(block.ecc[i]);
    }
    return result;
  }

  function blankMatrix() {
    return {
      modules: Array.from({ length: MODULE_COUNT }, () => new Array(MODULE_COUNT).fill(false)),
      reserved: Array.from({ length: MODULE_COUNT }, () => new Array(MODULE_COUNT).fill(false)),
    };
  }

  function setModule(qr, x, y, dark, reserve = true) {
    if (x < 0 || y < 0 || x >= MODULE_COUNT || y >= MODULE_COUNT) return;
    qr.modules[y][x] = Boolean(dark);
    if (reserve) qr.reserved[y][x] = true;
  }

  function reserve(qr, x, y) {
    if (x < 0 || y < 0 || x >= MODULE_COUNT || y >= MODULE_COUNT) return;
    qr.reserved[y][x] = true;
  }

  function addFinder(qr, x, y) {
    for (let dy = -1; dy <= 7; dy += 1) {
      for (let dx = -1; dx <= 7; dx += 1) {
        const xx = x + dx;
        const yy = y + dy;
        const inOuter = dx >= 0 && dx <= 6 && dy >= 0 && dy <= 6;
        const inCenter = dx >= 2 && dx <= 4 && dy >= 2 && dy <= 4;
        const dark = inOuter && (dx === 0 || dx === 6 || dy === 0 || dy === 6 || inCenter);
        setModule(qr, xx, yy, dark);
      }
    }
  }

  function addAlignment(qr, cx, cy) {
    for (let dy = -2; dy <= 2; dy += 1) {
      for (let dx = -2; dx <= 2; dx += 1) {
        const distance = Math.max(Math.abs(dx), Math.abs(dy));
        setModule(qr, cx + dx, cy + dy, distance !== 1);
      }
    }
  }

  function addFunctionPatterns(qr) {
    addFinder(qr, 0, 0);
    addFinder(qr, MODULE_COUNT - 7, 0);
    addFinder(qr, 0, MODULE_COUNT - 7);
    addAlignment(qr, 26, 26);

    for (let i = 8; i < MODULE_COUNT - 8; i += 1) {
      setModule(qr, i, 6, i % 2 === 0);
      setModule(qr, 6, i, i % 2 === 0);
    }

    setModule(qr, 8, MODULE_COUNT - 8, true);
    for (let i = 0; i < 9; i += 1) {
      reserve(qr, 8, i);
      reserve(qr, i, 8);
    }
    for (let i = MODULE_COUNT - 8; i < MODULE_COUNT; i += 1) reserve(qr, 8, i);
    for (let i = MODULE_COUNT - 7; i < MODULE_COUNT; i += 1) reserve(qr, i, 8);
  }

  function maskBit(mask, x, y) {
    switch (mask) {
      case 0: return (x + y) % 2 === 0;
      case 1: return y % 2 === 0;
      case 2: return x % 3 === 0;
      case 3: return (x + y) % 3 === 0;
      case 4: return (Math.floor(y / 2) + Math.floor(x / 3)) % 2 === 0;
      case 5: return ((x * y) % 2) + ((x * y) % 3) === 0;
      case 6: return (((x * y) % 2) + ((x * y) % 3)) % 2 === 0;
      case 7: return (((x + y) % 2) + ((x * y) % 3)) % 2 === 0;
      default: return false;
    }
  }

  function addData(qr, codewords, mask) {
    const bits = [];
    for (const byte of codewords) appendBits(bits, byte, 8);
    let bitIndex = 0;
    let upward = true;
    for (let right = MODULE_COUNT - 1; right >= 1; right -= 2) {
      if (right === 6) right -= 1;
      for (let vertical = 0; vertical < MODULE_COUNT; vertical += 1) {
        const y = upward ? MODULE_COUNT - 1 - vertical : vertical;
        for (let col = 0; col < 2; col += 1) {
          const x = right - col;
          if (qr.reserved[y][x]) continue;
          const raw = bitIndex < bits.length && bits[bitIndex] === 1;
          setModule(qr, x, y, raw !== maskBit(mask, x, y), false);
          bitIndex += 1;
        }
      }
      upward = !upward;
    }
  }

  function bchFormat(data) {
    let value = data << 10;
    const generator = 0x537;
    for (let i = 14; i >= 10; i -= 1) {
      if (((value >>> i) & 1) !== 0) value ^= generator << (i - 10);
    }
    return ((data << 10) | value) ^ 0x5412;
  }

  function addFormatBits(qr, mask) {
    const eclM = 0;
    const bits = bchFormat((eclM << 3) | mask);
    for (let i = 0; i <= 5; i += 1) setModule(qr, 8, i, ((bits >>> i) & 1) !== 0);
    setModule(qr, 8, 7, ((bits >>> 6) & 1) !== 0);
    setModule(qr, 8, 8, ((bits >>> 7) & 1) !== 0);
    setModule(qr, 7, 8, ((bits >>> 8) & 1) !== 0);
    for (let i = 9; i < 15; i += 1) setModule(qr, 14 - i, 8, ((bits >>> i) & 1) !== 0);

    for (let i = 0; i < 8; i += 1) setModule(qr, MODULE_COUNT - 1 - i, 8, ((bits >>> i) & 1) !== 0);
    for (let i = 8; i < 15; i += 1) setModule(qr, 8, MODULE_COUNT - 15 + i, ((bits >>> i) & 1) !== 0);
  }

  function makeMatrix(text) {
    const mask = 0;
    const qr = blankMatrix();
    addFunctionPatterns(qr);
    addData(qr, makeCodewords(text), mask);
    addFormatBits(qr, mask);
    return qr.modules;
  }

  function drawCanvas(container, text, options) {
    const size = options.width || options.height || DEFAULT_SIZE;
    const dark = options.colorDark || "#000000";
    const light = options.colorLight || "#ffffff";
    const quiet = 4;
    const modules = makeMatrix(text);
    const cellCount = MODULE_COUNT + quiet * 2;
    const scale = Math.max(1, Math.round(size / cellCount));
    const pixelSize = cellCount * scale;

    const canvas = document.createElement("canvas");
    canvas.width = pixelSize;
    canvas.height = pixelSize;
    canvas.style.width = `${pixelSize}px`;
    canvas.style.height = `${pixelSize}px`;
    canvas.setAttribute("aria-label", "QR kod za ulazak u sobu");

    const ctx = canvas.getContext("2d");
    ctx.imageSmoothingEnabled = false;
    ctx.fillStyle = light;
    ctx.fillRect(0, 0, pixelSize, pixelSize);
    ctx.fillStyle = dark;
    for (let y = 0; y < MODULE_COUNT; y += 1) {
      for (let x = 0; x < MODULE_COUNT; x += 1) {
        if (modules[y][x]) ctx.fillRect((x + quiet) * scale, (y + quiet) * scale, scale, scale);
      }
    }
    container.appendChild(canvas);
  }

  function QRCode(container, options) {
    if (!container) throw new Error("QRCode container is required.");
    const config = typeof options === "string" ? { text: options } : (options || {});
    const text = String(config.text || "");
    if (!text) throw new Error("QRCode text is required.");
    container.innerHTML = "";
    drawCanvas(container, text, config);
  }

  QRCode.CorrectLevel = { L: 1, M: 0, Q: 3, H: 2 };
  window.QRCode = QRCode;
})();
